mapper.select:
SELECT cp.*,
       m.major_name  AS majorName,
       am.major_name AS admissionMajorName,
       a.real_name   AS operatorName
FROM candidate_push cp
LEFT JOIN major m   ON cp.major_id = m.major_id
LEFT JOIN major am  ON cp.admission_major_id = am.major_id
LEFT JOIN account a ON cp.operator_id = a.account_id
WHERE cp.school_id = #{schoolId}

    AND cp.status IN

        #{s}



    AND cp.total_score >= #{minScore}


    AND cp.total_score <= #{maxScore}


    AND cp.intention ILIKE '%' || #{intentionKeyword} || '%'


    AND cp.nationality = #{nationality}


    AND cp.pushed_at >= #{pushTimeStart}


    AND cp.pushed_at <= #{pushTimeEnd}


    AND (cp.major_id = #{majorId} OR cp.admission_major_id = #{majorId})


    AND cp.push_round = #{round}

ORDER BY

        cp.total_score
        cp.pushed_at


        ASC
        DESC

SELECT * FROM candidate_push
WHERE status = 'CONDITIONAL'
  AND condition_deadline <= #{now}
